(function() {
    const style = document.createElement('style');
    style.innerHTML = `
.btn-outline-info, .btn-warning {
  --bs-btn-hover-color: white !important;
  --bs-btn-active-color: white !important;
}

.btn-warning {
  --bs-btn-color: white;
}

.checklist {
  padding: 6px 15px;
}

html[data-theme="dark"] body {
  color: rgb(219, 219, 219) !important;
  background-color: #ffffff00;
}

html[data-theme="dark"] .section-title {
  color: white;
}

html[data-theme="dark"] .checklist {
  background-color: #1c1c1c;
  margin: 2px 0;
  border-left: 5px solid #787B86;
  color: white ;
}

html[data-theme="dark"] .checklist:hover {
  background-color: #252525;
}

html[data-theme="dark"] .checklist .option.btn-outline-info {
  --bs-btn-color: #cfcfcf;
  --bs-btn-border-color: #cfcfcf;
  --bs-btn-hover-bg: #787B86;
  --bs-btn-hover-border-color: #cfcfcf;
  --bs-btn-active-bg: #787B86;
  --bs-btn-active-border-color: #787B86;
  --bs-btn-disabled-color: #cfcfcf;
  --bs-btn-disabled-border-color: #cfcfcf;
}

html.theme-light .checklist {
  border-bottom: 1px solid #f2f2f2;
}

html.theme-light .checklist:hover {
  background-color: #f2f2f2;
  border-left: 5px solid #787B86;
  padding-left: 10px;
}

.checklist .checklist-text {
  display: inline-block;
  margin-left: 5px;
}

.saf_container #score {
  border-radius: 5px;
  padding: 5px 8px;
  display: inline-block;
  color: white;
  position: absolute;
  right: 10px;
  transition-duration: .5s;
}

.widgetbar-widget-detail [class^="backBtn-"], .widgetbar-widget-detail [class^="rightSlot-"] {
  display: none;
}

.widgetbar-widgetbody {
  overflow: auto;
}

.widgetbar-widget-detail [class*="empty-"]{
  overflow: visible;
}

.widgetbar-widget-detail [class*="emptyState-"] {
  padding: 20px;
}

.widgetbar-widget-detail [class*="groupDetailed-"] {
  height: auto;
}

.widgetbar-widget-detail [class^="itemsContainer-"] {
  flex-grow: 0;
}

html.theme-dark .widgetbar-widget.widgetbar-widget-detail {
  background-color: #0f0f0f !important;
}

* {
  box-sizing: unset;
}

.widgetbar-widgetbody *, .widgetbar-widgetbody {
  box-sizing: border-box;
}

.widgetbar-widgetbody {
  overflow-y: auto !important;
  display: block !important;
}

    `;
    document.head.appendChild(style);
})();


